//! demoReview 3D replay viewer — Bevy/WASM port of the Three.js app generated by
//! build3d_app.py (branch feature/3d-replay). The HTML page owns the UI (scrubber,
//! round selector, speed buttons, labels, timeline markers, flash overlay div);
//! this crate owns the 3D scene and playback clock. See www/index.html for the
//! JS <-> WASM control interface documentation.

mod coords;
mod orbit;
mod scene;
mod state;
mod util;

pub use coords::*;

use bevy::core_pipeline::tonemapping::Tonemapping;
use bevy::prelude::*;
use wasm_bindgen::prelude::*;

use state::{
    ang_lerp, lerp, push_control, sample_pos, ControlMsg, GreyboxTag, PlayerBody, PlayerNose,
    RoundState, UtilTag, Viewer, QUEUE,
};
use util::{tracer_frame, util_frame, UtilKind};

// ---------------------------------------------------------------------------
// JS -> WASM control surface (exported); see www/index.html for the caller side
// ---------------------------------------------------------------------------

/// Start the Bevy app on the given canvas (CSS selector). Returns immediately;
/// all further control goes through the queued messages below.
#[wasm_bindgen]
pub fn run(canvas_selector: String) {
    console_error_panic_hook::set_once();
    App::new()
        .insert_resource(ClearColor(util::hex_color("#0b0e14")))
        .insert_resource(Viewer::default())
        .insert_resource(orbit::OrbitCam::default())
        .insert_resource(LabelsOut::default())
        .insert_resource(TracersOut::default())
        .add_plugins(DefaultPlugins.set(WindowPlugin {
            primary_window: Some(Window {
                canvas: Some(canvas_selector),
                fit_canvas_to_parent: true,
                prevent_default_event_handling: false,
                ..default()
            }),
            ..default()
        }))
        .add_systems(Startup, setup)
        .add_systems(
            Update,
            (
                drain_controls,
                advance_clock,
                update_players,
                update_utility,
                draw_grid,
                orbit::orbit_camera,
                report_frame,
            )
                .chain(),
        )
        .run();
}

/// Feed manifest.json's text (greybox + team colors + camera framing).
#[wasm_bindgen]
pub fn load_manifest(json: String) {
    push_control(ControlMsg::LoadManifest(json));
}

/// Feed one round's raw .3dr bytes. Decodes synchronously and returns the round's
/// header JSON (players, weaponTable, utility, nSamples, ...) for the page UI.
#[wasm_bindgen]
pub fn load_round(bytes: &[u8]) -> Result<String, JsValue> {
    let dec = c2r3::decode_round(bytes).map_err(|e| JsValue::from_str(&e.to_string()))?;
    let header = serde_json::to_string(&dec.header).map_err(|e| JsValue::from_str(&e.to_string()))?;
    push_control(ControlMsg::LoadRound(Box::new(dec)));
    Ok(header)
}

#[wasm_bindgen]
pub fn seek(t: f64) {
    push_control(ControlMsg::Seek(t));
}

#[wasm_bindgen]
pub fn set_playing(playing: bool) {
    push_control(ControlMsg::SetPlaying(playing));
}

#[wasm_bindgen]
pub fn set_speed(speed: f64) {
    push_control(ControlMsg::SetSpeed(speed));
}

/// `?flash=<playerName>` deep-link: whose flash channel drives the page overlay.
#[wasm_bindgen]
pub fn set_flash_focus(name: Option<String>) {
    push_control(ControlMsg::SetFlashFocus(name));
}

// ---------------------------------------------------------------------------
// WASM -> JS per-frame report. Flat f32 payload (see index.html for the layout):
// [clock, duration, playing, flashOpacity, nPlayers, nTracers,
//  {x, y, visible} * nPlayers,            (normalized viewport coords)
//  {utilIdx, x, y, opacity} * nTracers]
// ---------------------------------------------------------------------------

#[cfg(target_arch = "wasm32")]
#[wasm_bindgen]
extern "C" {
    #[wasm_bindgen(js_namespace = window, js_name = __replayFrame)]
    fn replay_frame(data: &[f32]);
}

#[cfg(not(target_arch = "wasm32"))]
fn replay_frame(_data: &[f32]) {}

/// Interpolated foot positions from update_players, consumed by report_frame.
#[derive(Resource, Default)]
struct LabelsOut(Vec<(Vec3, bool)>);

/// Tracer label anchors from update_utility: (utility index, tip, opacity).
#[derive(Resource, Default)]
struct TracersOut(Vec<(usize, Vec3, f32)>);

